class Solution {
public:
    int appendCharacters(string s, string t) {
        int t_ptr = 0;
        for (char c : s) {
            if (t_ptr < t.size() && c == t[t_ptr]) {
                t_ptr++;
            }
        }
        return t.size() - t_ptr;
    }
};

